CREATE OR REPLACE VIEW `vplantstatus` AS select `plant`.`plantId` AS `plantId`,`plant`.`acquisitionDate` AS `acquisitionDate`,`plant`.`plantTag` AS `plantTag`,(case when (`taxon`.`isSystemManaged` = 1) then concat(`genus`.`genusName`,' sp.') when (`taxon`.`speciesName` is not null) then concat(`genus`.`genusName`,' ',`taxon`.`speciesName`) when (`taxon`.`hybridName` is not null) then concat(`genus`.`genusName`,' ',`taxon`.`hybridName`) else `genus`.`genusName` end) AS `displayName`,`taxon`.`isActive` AS `taxonIsActive`,`genus`.`isActive` AS `genusIsActive`,`loc`.`locationName` AS `locationName`,`lastflower`.`lastFloweringDate` AS `lastFloweringDate`,`lastrepot`.`lastRepotDate` AS `lastRepotDate`,`growthmedium`.`name` AS `currentGrowthMediumName`,`lastfeed`.`lastFeedDateTime` AS `lastFeedDateTime`,`lastfeed`.`lastFeedTypeDisplayName` AS `lastFeedTypeDisplayName` from ((((((((`plant` left join `taxon` on((`plant`.`taxonId` = `taxon`.`taxonId`))) left join `genus` on((`taxon`.`genusId` = `genus`.`genusId`))) left join (select `ordered`.`plantId` AS `plantId`,`ordered`.`locationId` AS `locationId` from (select `lochistory`.`plantId` AS `plantId`,`lochistory`.`locationId` AS `locationId`,row_number() OVER (PARTITION BY `lochistory`.`plantId` ORDER BY `lochistory`.`startDateTime` desc )  AS `rn` from `plantlocationhistory` `lochistory` where (`lochistory`.`isActive` = 1)) `ordered` where (`ordered`.`rn` = 1)) `currentlocation` on((`plant`.`plantId` = `currentlocation`.`plantId`))) left join `location` `loc` on((`loc`.`locationId` = `currentlocation`.`locationId`))) left join (select `ordered`.`plantId` AS `plantId`,`ordered`.`startDate` AS `lastFloweringDate` from (select `flowering`.`plantId` AS `plantId`,`flowering`.`startDate` AS `startDate`,row_number() OVER (PARTITION BY `flowering`.`plantId` ORDER BY `flowering`.`startDate` desc )  AS `rn` from `flowering` where (`flowering`.`isActive` = 1)) `ordered` where (`ordered`.`rn` = 1)) `lastflower` on((`plant`.`plantId` = `lastflower`.`plantId`))) left join (select `ordered`.`plantId` AS `plantId`,`ordered`.`repotDate` AS `lastRepotDate`,`ordered`.`newGrowthMediumId` AS `newGrowthMediumId` from (select `repotting`.`plantId` AS `plantId`,`repotting`.`repotDate` AS `repotDate`,`repotting`.`newGrowthMediumId` AS `newGrowthMediumId`,row_number() OVER (PARTITION BY `repotting`.`plantId` ORDER BY `repotting`.`repotDate` desc )  AS `rn` from `repotting` where (`repotting`.`isActive` = 1)) `ordered` where (`ordered`.`rn` = 1)) `lastrepot` on((`plant`.`plantId` = `lastrepot`.`plantId`))) left join `growthmedium` on((`growthmedium`.`growthMediumId` = `lastrepot`.`newGrowthMediumId`))) left join (select `ordered`.`plantId` AS `plantId`,`ordered`.`eventDateTime` AS `lastFeedDateTime`,`ordered`.`displayName` AS `lastFeedTypeDisplayName` from (select `eventorder`.`plantId` AS `plantId`,`eventorder`.`eventDateTime` AS `eventDateTime`,`obstype`.`displayName` AS `displayName`,row_number() OVER (PARTITION BY `eventorder`.`plantId` ORDER BY `eventorder`.`eventDateTime` desc )  AS `rn` from (`plantevent` `eventorder` join `observationtype` `obstype` on(((`obstype`.`Id` = `eventorder`.`observationTypeId`) and (`obstype`.`isActive` = 1)))) where ((`eventorder`.`isActive` = 1) and (`obstype`.`typeCode` like 'OBS_FEED%'))) `ordered` where (`ordered`.`rn` = 1)) `lastfeed` on((`plant`.`plantId` = `lastfeed`.`plantId`))) where ((`plant`.`endDate` is null) and (`plant`.`isActive` = 1));

